// Функция для определения яркости цвета
const getColorBrightness = (hexColor: string): number => {
	// Убираем # если есть
	const hex = hexColor.replace('#', '');

	// Преобразуем hex в RGB
	const red = parseInt(hex.substr(0, 2), 16);
	const green = parseInt(hex.substr(2, 2), 16);
	const blue = parseInt(hex.substr(4, 2), 16);

	// Формула относительной яркости (ITU-R BT.709)
	return (0.2126 * red + 0.7152 * green + 0.0722 * blue) / 255;
};

// Функция для определения, нужен ли светлый или темный текст
export const isDarkColor = (hexColor: string | undefined): boolean => {
	if (!hexColor) {
		return false;
	}
	return getColorBrightness(hexColor) < 0.5;
};
